import re

def validate_iam_role_arn(arn: str) -> bool:
    pattern = (
        r"^arn:aws"                          # Partitions for standard AWS
        r":(us-east-1|[a-z]{2}-[a-z]+-[0-9]+)"  # Region (e.g., us-east-1, eu-west-2)
        r":iam"                              # Service name
        r":role"                             # Resource type
        r":([a-z0-9-_]+\/?)([^:]*):([a-z0-9-_.]+)$"  # Account ID, Role Name, ARN
    )
    return bool(re.fullmatch(pattern, arn))
